1	`include "common_defs.v"
2	
3	module dot11 (
4	    input clock,
5	    input enable,
6	    input reset,
7	
8	    // setting registers
9	    input set_stb,
10	    input [7:0] set_addr,
11	    input [31:0] set_data,
12	
13	    // INPUT: I/Q sample
14	    input [31:0] sample_in,
15	    input sample_in_strobe,
16	
17	    // OUTPUT: bytes and FCS status
18	    output reg pkt_begin,
19	    output reg pkt_ht,
20	    output reg [7:0] pkt_rate,
21	    output reg [15:0] pkt_len,
22	    output byte_out_strobe,
23	    output [7:0] byte_out,
24	    output reg fcs_out_strobe,
25	    output reg fcs_ok,
26	
27	    /////////////////////////////////////////////////////////
28	    // DEBUG PORTS
29	    /////////////////////////////////////////////////////////
30	    
31	    // decode status
32	    output reg [3:0] state,
33	    output reg [3:0] status_code,
34	    output state_changed,
35	
36	    // power trigger
37	    output power_trigger,
38	
39	    // sync short
40	    output short_preamble_detected,
41	    output [31:0] phase_offset,
42	
43	    // sync long
44	    output [31:0] sync_long_metric,
45	    output sync_long_metric_stb,
46	    output long_preamble_detected,
47	    output [31:0] sync_long_out,
48	    output sync_long_out_strobe,
49	    output [2:0] sync_long_state,
50	
51	    // equalizer
52	    output [31:0] equalizer_out,
53	    output equalizer_out_strobe,
54	    output [2:0] equalizer_state,
55	
56	    // legacy signal info
57	    output reg legacy_sig_stb,
58	    output [3:0] legacy_rate,
59	    output legacy_sig_rsvd,
60	    output [11:0] legacy_len,
61	    output legacy_sig_parity,
62	    output legacy_sig_parity_ok,
63	    output [5:0] legacy_sig_tail,
64	
65	    // ht signal info
66	    output reg ht_sig_stb,
67	    output [6:0] ht_mcs,
68	    output ht_cbw,
69	    output [15:0] ht_len,
70	    output ht_smoothing,
71	    output ht_not_sounding,
72	    output ht_aggregation,
73	    output [1:0] ht_stbc,
74	    output ht_fec_coding,
75	    output ht_sgi,
76	    output [1:0] ht_num_ext,
77	    output reg ht_sig_crc_ok,
78	
79	    // decoding pipeline
80	    output [5:0] demod_out,
81	    output demod_out_strobe,
82	
83	    output [1:0] deinterleave_out,
84	    output deinterleave_out_strobe,
85	
86	    output conv_decoder_out,
87	    output conv_decoder_out_stb,
88	
89	    output descramble_out,
90	    output descramble_out_strobe
91	);
92	
93	`include "common_params.v"
94	
95	
96	////////////////////////////////////////////////////////////////////////////////
97	// Shared rotation LUT for sync_long and equalizer
98	////////////////////////////////////////////////////////////////////////////////
99	wire [`ROTATE_LUT_LEN_SHIFT-1:0] sync_long_rot_addr;
100	wire [31:0] sync_long_rot_data;
101	
102	wire [`ROTATE_LUT_LEN_SHIFT-1:0] eq_rot_addr;
103	wire [31:0] eq_rot_data;
104	
105	rot_lut rot_lut_inst (
106	    .clka(clock),
107	    .addra(sync_long_rot_addr),
108	    .douta(sync_long_rot_data),
109	
110	    .clkb(clock),
111	    .addrb(eq_rot_addr),
112	    .doutb(eq_rot_data)
113	);
114	////////////////////////////////////////////////////////////////////////////////
115	
116	
117	
118	////////////////////////////////////////////////////////////////////////////////
119	// Shared phase module for sync_short and equalizer
120	////////////////////////////////////////////////////////////////////////////////
121	wire [31:0] sync_short_phase_in_i;
122	wire [31:0] sync_short_phase_in_q;
123	wire sync_short_phase_in_stb;
124	wire [31:0] sync_short_phase_out;
125	wire sync_short_phase_out_stb;
126	
127	wire [31:0] eq_phase_in_i;
128	wire [31:0] eq_phase_in_q;
129	wire eq_phase_in_stb;
130	wire [31:0] eq_phase_out;
131	wire eq_phase_out_stb;
132	
133	wire[31:0] phase_in_i = state == S_SYNC_SHORT?
134	    sync_short_phase_in_i: eq_phase_in_i;
135	wire[31:0] phase_in_q = state == S_SYNC_SHORT?
136	    sync_short_phase_in_q: eq_phase_in_q;
137	wire phase_in_stb = state == S_SYNC_SHORT?
138	    sync_short_phase_in_stb: eq_phase_in_stb;
139	
140	wire [31:0] phase_out;
141	wire phase_out_stb;
142	
143	assign sync_short_phase_out = phase_out;
144	assign sync_short_phase_out_stb = phase_out_stb;
145	assign eq_phase_out = phase_out;
146	assign eq_phase_out_stb = phase_out_stb;
147	
148	phase phase_inst (
149	    .clock(clock),
150	    .reset(reset),
151	    .enable(enable),
152	
153	    .in_i(phase_in_i),
154	    .in_q(phase_in_q),
155	    .input_strobe(phase_in_stb),
156	
157	    .phase(phase_out),
158	    .output_strobe(phase_out_stb)
159	);
160	////////////////////////////////////////////////////////////////////////////////
161	
162	
163	reg sync_short_reset;
164	reg sync_long_reset;
165	wire sync_short_enable = state == S_SYNC_SHORT;
166	reg sync_long_enable;
167	
168	reg equalizer_reset;
169	reg equalizer_enable;
170	
171	reg ht_next;
172	
173	wire eq_out_stb_delayed;
174	wire [15:0] eq_out_i = equalizer_out[31:16];
175	wire [15:0] eq_out_q = equalizer_out[15:0];
176	wire [15:0] eq_out_i_delayed;
177	wire [15:0] eq_out_q_delayed;
178	reg [15:0] abs_eq_i;
179	reg [15:0] abs_eq_q;
180	reg [3:0] rot_eq_count;
181	reg [3:0] normal_eq_count;
182	
183	// OFDM control
184	reg ofdm_reset;
185	reg ofdm_enable;
186	reg ofdm_in_stb;
187	reg [15:0] ofdm_in_i;
188	reg [15:0] ofdm_in_q;
189	
190	reg do_descramble;
191	reg [31:0] num_bits_to_decode;
192	reg short_gi;
193	
194	reg [3:0] old_state;
195	assign state_changed = state != old_state;
196	
197	// SIGNAL information
198	reg [23:0] signal_bits;
199	reg [31:0] byte_count;
200	
201	assign legacy_rate = signal_bits[3:0];
202	assign legacy_sig_rsvd = signal_bits[4];
203	assign legacy_len = signal_bits[16:5];
204	assign legacy_sig_parity = signal_bits[17];
205	assign legacy_sig_tail = signal_bits[23:18];
206	assign legacy_sig_parity_ok = ~^signal_bits[17:0];
207	
208	
209	// HT-SIG information
210	reg [23:0] ht_sig1;
211	reg [23:0] ht_sig2;
212	
213	assign ht_mcs = ht_sig1[6:0];
214	assign ht_cbw = ht_sig1[7];
215	assign ht_len = ht_sig1[23:8];
216	
217	assign ht_smoothing = ht_sig2[0];
218	assign ht_not_sounding = ht_sig2[1];
219	assign ht_aggregation = ht_sig2[3];
220	assign ht_stbc = ht_sig2[5:4];
221	assign ht_fec_coding = ht_sig2[6];
222	assign ht_sgi = ht_sig2[7];
223	assign ht_num_ext = ht_sig2[9:8];
224	
225	
226	wire ht_rsvd = ht_sig2[2];
227	wire [7:0] crc = ht_sig2[17:10];
228	wire [5:0] ht_sig_tail = ht_sig2[23:18];
229	
230	
231	reg crc_in_stb;
232	reg crc_in;
233	reg [7:0] crc_count;
234	reg crc_reset;
235	wire [7:0] crc_out;
236	
237	reg [31:0] sample_count;
238	
239	wire fcs_enable = state == S_DECODE_DATA && byte_out_strobe;
240	wire fcs_reset = state_changed && state == S_DECODE_DATA;
241	wire [7:0] byte_reversed;
242	wire [31:0] pkt_fcs;
243	
244	assign byte_reversed[0] = byte_out[7];
245	assign byte_reversed[1] = byte_out[6];
246	assign byte_reversed[2] = byte_out[5];
247	assign byte_reversed[3] = byte_out[4];
248	assign byte_reversed[4] = byte_out[3];
249	assign byte_reversed[5] = byte_out[2];
250	assign byte_reversed[6] = byte_out[1];
251	assign byte_reversed[7] = byte_out[0];
252	
253	reg [15:0] sync_long_out_count;
254	
255	integer i;
256	
257	power_trigger power_trigger_inst (
258	    .clock(clock),
259	    .enable(enable),
260	    .reset(reset),
261	
262	    .sample_in(sample_in),
263	    .sample_in_strobe(sample_in_strobe),
264	
265	    .set_stb(set_stb),
266	    .set_addr(set_addr),
267	    .set_data(set_data),
268	
269	    .trigger(power_trigger)
270	);
271	
272	sync_short sync_short_inst (
273	    .clock(clock),
274	    .reset(reset | sync_short_reset),
275	    .enable(enable & sync_short_enable),
276	
277	    .set_stb(set_stb),
278	    .set_addr(set_addr),
279	    .set_data(set_data),
280	
281	    .sample_in(sample_in),
282	    .sample_in_strobe(sample_in_strobe),
283	
284	    .phase_in_i(sync_short_phase_in_i),
285	    .phase_in_q(sync_short_phase_in_q),
286	    .phase_in_stb(sync_short_phase_in_stb),
287	
288	    .phase_out(sync_short_phase_out),
289	    .phase_out_stb(sync_short_phase_out_stb),
290	
291	    .short_preamble_detected(short_preamble_detected),
292	    .phase_offset(phase_offset)
293	);
294	
295	sync_long sync_long_inst (
296	    .clock(clock),
297	    .reset(reset | sync_long_reset),
298	    .enable(enable & sync_long_enable),
299	
300	    .set_stb(set_stb),
301	    .set_addr(set_addr),
302	    .set_data(set_data),
303	
304	    .sample_in(sample_in),
305	    .sample_in_strobe(sample_in_strobe),
306	    .phase_offset(phase_offset),
307	    .short_gi(short_gi),
308	
309	    .rot_addr(sync_long_rot_addr),
310	    .rot_data(sync_long_rot_data),
311	
312	    .metric(sync_long_metric),
313	    .metric_stb(sync_long_metric_stb),
314	    .long_preamble_detected(long_preamble_detected),
315	    .state(sync_long_state),
316	
317	    .sample_out(sync_long_out),
318	    .sample_out_strobe(sync_long_out_strobe)
319	);
320	
321	equalizer equalizer_inst (
322	    .clock(clock),
323	    .reset(reset | equalizer_reset),
324	    .enable(enable & equalizer_enable),
325	
326	    .sample_in(sync_long_out),
327	    .sample_in_strobe(sync_long_out_strobe),
328	    .ht_next(ht_next),
329	
330	    .phase_in_i(eq_phase_in_i),
331	    .phase_in_q(eq_phase_in_q),
332	    .phase_in_stb(eq_phase_in_stb),
333	
334	    .phase_out(eq_phase_out),
335	    .phase_out_stb(eq_phase_out_stb),
336	
337	    .rot_addr(eq_rot_addr),
338	    .rot_data(eq_rot_data),
339	
340	    .sample_out(equalizer_out),
341	    .sample_out_strobe(equalizer_out_strobe),
342	
343	    .state(equalizer_state)
344	);
345	
346	
347	delayT #(.DATA_WIDTH(33), .DELAY(6)) eq_delay_inst (
348	    .clock(clock),
349	    .reset(reset),
350	
351	    .data_in({equalizer_out_strobe, equalizer_out}),
352	    .data_out({eq_out_stb_delayed, eq_out_i_delayed, eq_out_q_delayed})
353	);
354	
355	
356	ofdm_decoder ofdm_decoder_inst (
357	    .clock(clock),
358	    .reset(reset|ofdm_reset),
359	    .enable(enable & ofdm_enable),
360	
361	    .sample_in({ofdm_in_i, ofdm_in_q}),
362	    .sample_in_strobe(ofdm_in_stb),
363	
364	    .do_descramble(do_descramble),
365	    .num_bits_to_decode(num_bits_to_decode),
366	    .rate(pkt_rate),
367	
368	    .byte_out(byte_out),
369	    .byte_out_strobe(byte_out_strobe),
370	
371	    .demod_out(demod_out),
372	    .demod_out_strobe(demod_out_strobe),
373	
374	    .deinterleave_out(deinterleave_out),
375	    .deinterleave_out_strobe(deinterleave_out_strobe),
376	
377	    .conv_decoder_out(conv_decoder_out),
378	    .conv_decoder_out_stb(conv_decoder_out_stb),
379	
380	    .descramble_out(descramble_out),
381	    .descramble_out_strobe(descramble_out_strobe)
382	);
383	
384	ht_sig_crc crc_inst (
385	    .clock(clock),
386	    .enable(enable),
387	    .reset(reset | crc_reset),
388	
389	    .bit(crc_in),
390	    .input_strobe(crc_in_stb),
391	    .crc(crc_out)
392	);
393	
394	crc32 fcs_inst (
395	    .clk(clock),
396	    .crc_en(enable & fcs_enable),
397	    .rst(reset | fcs_reset),
398	    .data_in(byte_reversed),
399	    .crc_out(pkt_fcs)
400	);
401	
402	
403	always @(posedge clock) begin
404	    if (reset) begin
405	        status_code <= E_OK;
406	        state <= S_WAIT_POWER_TRIGGER;
407	        old_state <= 0;
408	
409	        sync_short_reset <= 0;
410	
411	        sync_long_reset <= 0;
412	        sync_long_enable <= 0;
413	
414	        byte_count <= 0;
415	
416	        pkt_begin <= 0;
417	        pkt_ht <= 0;
418	
419	
420	        rot_eq_count <= 0;
421	        normal_eq_count <= 0;
422	        abs_eq_i <= 0;
423	        abs_eq_q <= 0;
424	
425	        do_descramble <= 0;
426	        num_bits_to_decode <= 0;
427	        short_gi <= 0;
428	        pkt_rate <= 0;
429	
430	        equalizer_reset <= 0;
431	        equalizer_enable <= 0;
432	        ht_next <= 0;
433	
434	        pkt_len <= 0;
435	
436	        ofdm_reset <= 0;
437	        ofdm_enable <= 0;
438	        ofdm_in_stb <= 0;
439	        ofdm_in_i <= 0;
440	        ofdm_in_q <= 0;
441	
442	        sample_count <= 0;
443	
444	        sync_long_out_count <= 0;
445	
446	        signal_bits <= 0;
447	        legacy_sig_stb <= 0;
448	
449	        ht_sig1 <= 0;
450	        ht_sig2 <= 0;
451	        crc_in_stb <= 0;
452	        crc_in <= 0;
453	        crc_count <= 0;
454	        crc_reset <= 0;
455	        ht_sig_crc_ok <= 0;
456	        ht_sig_stb <= 0;
457	
458	        fcs_out_strobe <= 0;
459	        fcs_ok <= 0;
460	    end else if (enable) begin
461	        old_state <= state;
462	
463	        case(state)
464	            S_WAIT_POWER_TRIGGER: begin
465	                sync_long_enable <= 0;
466	                equalizer_enable <= 0;
467	                ofdm_enable <= 0;
468	
469	                if (power_trigger) begin
470	                    `ifdef DEBUG_PRINT
471	                        $display("Power triggered.");
472	                    `endif
473	                    sync_short_reset <= 1;
474	                    state <= S_SYNC_SHORT;
475	                end
476	            end
477	
478	            S_SYNC_SHORT: begin
479	                if (sync_short_reset) begin
480	                    sync_short_reset <= 0;
481	                end
482	
483	                if (~power_trigger) begin
484	                    // power level drops before finding STS
485	                    state <= S_WAIT_POWER_TRIGGER;
486	                end
487	
488	                if (short_preamble_detected) begin
489	                    `ifdef DEBUG_PRINT
490	                        $display("Short preamble detected");
491	                    `endif
492	                    sync_long_reset <= 1;
493	                    sync_long_enable <= 1;
494	                    sample_count <= 0;
495	                    state <= S_SYNC_LONG;
496	                end
497	                
498	            end
499	
500	            S_SYNC_LONG: begin
501	                if (sync_long_reset) begin
502	                    sync_long_reset <= 0;
503	                end
504	
505	                if (sample_in_strobe) begin
506	                    sample_count <= sample_count + 1;
507	                end
508	                if (sample_count > 320) begin
509	                    state <= S_WAIT_POWER_TRIGGER;
510	                end
511	
512	                if (~power_trigger) begin
513	                    state <= S_WAIT_POWER_TRIGGER;
514	                end
515	
516	                if (long_preamble_detected) begin
517	                    pkt_rate <= {1'b0, 3'b0, 4'b1011};
518	                    do_descramble <= 0;
519	                    num_bits_to_decode <= 48;
520	
521	                    ofdm_reset <= 1;
522	                    ofdm_enable <= 1;
523	
524	                    equalizer_enable <= 1;
525	                    equalizer_reset <= 1;
526	
527	                    byte_count <= 0;
528	                    state <= S_DECODE_SIGNAL;
529	                end
530	            end
531	
532	            S_DECODE_SIGNAL: begin
533	                if (ofdm_reset) begin
534	                    ofdm_reset <= 0;
535	                end
536	
537	                if (equalizer_reset) begin
538	                    equalizer_reset <= 0;
539	                end
540	
541	                ofdm_in_stb <= equalizer_out_strobe;
542	                ofdm_in_i <= eq_out_i;
543	                ofdm_in_q <= eq_out_q;
544	
545	                if (byte_out_strobe) begin
546	                    signal_bits <= {byte_out, signal_bits[23:8]};
547	                    byte_count <= byte_count + 1;
548	                end
549	
550	                if (byte_count == 3) begin
551	                    byte_count <= 0;
552	                    `ifdef DEBUG_PRINT
553	                        $display("[SIGNAL] rate = %04b, ", legacy_rate,
554	                            "length = %012b (%d), ", legacy_len, legacy_len,
555	                            "parity = %b, ", legacy_sig_parity,
556	                            "tail = %6b", legacy_sig_tail);
557	                    `endif
558	                    ofdm_reset <= 1;
559	                    state <= S_CHECK_SIGNAL;
560	                end
561	            end
562	
563	            S_CHECK_SIGNAL: begin
564	                if (ofdm_reset) begin
565	                    ofdm_reset <= 0;
566	                end
567	
568	                if (~legacy_sig_parity_ok) begin
569	                    status_code <= E_PARITY_FAIL;
570	                    state <= S_SIGNAL_ERROR;
571	                end else if (legacy_sig_rsvd) begin
572	                    status_code <= E_WRONG_RSVD;
573	                    state <= S_SIGNAL_ERROR;
574	                end else if (|legacy_sig_tail) begin
575	                    status_code <= E_WRONG_TAIL;
576	                    state <= S_SIGNAL_ERROR;
577	                end else begin
578	                    legacy_sig_stb <= 1;
579	                    status_code <= E_OK;
580	                    if (legacy_rate == 4'b1011) begin
581	                        abs_eq_i <= 0;
582	                        abs_eq_q <= 0;
583	                        rot_eq_count <= 0;
584	                        normal_eq_count <= 0;
585	                        state <= S_DETECT_HT;
586	                    end else begin
587	                        pkt_rate <= {1'b0, 3'b0, legacy_rate};
588	                        num_bits_to_decode <= (legacy_len+3)<<4;
589	                        do_descramble <= 1;
590	                        ofdm_reset <= 1;
591	                        byte_count <= 0;
592	                        pkt_len <= legacy_len;
593	                        byte_count <= 0;
594	                        pkt_begin <= 1;
595	                        pkt_ht <= 0;
596	                        state <= S_DECODE_DATA;
597	                    end
598	                end
599	            end
600	
601	            S_SIGNAL_ERROR: begin
602	                state <= S_WAIT_POWER_TRIGGER;
603	            end
604	
605	            S_DETECT_HT: begin
606	                legacy_sig_stb <= 0;
607	
608	                if (equalizer_out_strobe) begin
609	                    abs_eq_i <= eq_out_i[15]? ~eq_out_i+1: eq_out_i;
610	                    abs_eq_q <= eq_out_q[15]? ~eq_out_q+1: eq_out_q;
611	                    if (abs_eq_q > abs_eq_i) begin
612	                        rot_eq_count <= rot_eq_count + 1;
613	                    end else begin
614	                        normal_eq_count <= normal_eq_count + 1;
615	                    end
616	                end
617	
618	                if (rot_eq_count >= 4) begin
619	                    // HT-SIG detected
620	                    byte_count <= 0;
621	                    pkt_rate <= {1'b0, 3'b0, 4'b1011};
622	                    num_bits_to_decode <= 96;
623	                    do_descramble <= 0;
624	                    ofdm_reset <= 1;
625	                    state <= S_HT_SIGNAL;
626	                end else if (normal_eq_count > 4) begin
627	                    pkt_len <= legacy_len;
628	                    num_bits_to_decode <= (legacy_len+3)<<4;
629	                    do_descramble <= 1;
630	                    ofdm_reset <= 1;
631	                    byte_count <= 0;
632	                    pkt_begin <= 1;
633	                    pkt_ht <= 0;
634	                    state <= S_DECODE_DATA;
635	                end
636	            end
637	
638	            S_HT_SIGNAL: begin
639	                if (ofdm_reset) begin
640	                    ofdm_reset <= 0;
641	                end
642	
643	                ofdm_in_stb <= eq_out_stb_delayed;
644	                // rotate clockwise by 90 degree
645	                ofdm_in_i <= eq_out_q_delayed;
646	                ofdm_in_q <= ~eq_out_i_delayed+1;
647	
648	                if (byte_out_strobe) begin
649	                    if (byte_count < 3) begin
650	                        ht_sig1 <= {byte_out, ht_sig1[23:8]};
651	                    end else begin
652	                        ht_sig2 <= {byte_out, ht_sig2[23:8]};
653	                    end
654	                    byte_count <= byte_count + 1;
655	                end
656	
657	                if (byte_count == 6) begin
658	                    byte_count <= 0;
659	                    `ifdef DEBUG_PRINT
660	                        $display("[HT SIGNAL] mcs = %07b (%d), ", ht_mcs, ht_mcs,
661	                            "CBW: %d, ", ht_cbw? 40: 20,
662	                            "length = %012b (%d), ", ht_len, ht_len,
663	                            "rsvd = %d, ", ht_rsvd,
664	                            "aggr = %d, ", ht_aggregation,
665	                            "stbd = %02b, ", ht_stbc,
666	                            "fec = %d, ", ht_fec_coding,
667	                            "sgi = %d, ", ht_sgi,
668	                            "num_ext = %d, ", ht_num_ext,
669	                            "crc = %08b, ", crc,
670	                            "tail = %06b", ht_sig_tail);
671	                    `endif
672	                    crc_count <= 0;
673	                    crc_reset <= 1;
674	                    crc_in_stb <= 0;
675	                    ht_sig_crc_ok <= 0;
676	                    state <= S_CHECK_HT_SIG_CRC;
677	                end
678	            end
679	
680	            S_CHECK_HT_SIG_CRC: begin
681	                crc_reset <= 0;
682	                crc_count <= crc_count + 1;
683	
684	                if (crc_count < 24) begin
685	                    crc_in_stb <= 1;
686	                    crc_in <= ht_sig1[crc_count];
687	                end else if (crc_count < 34) begin
688	                    crc_in_stb <= 1;
689	                    crc_in <= ht_sig2[crc_count-24];
690	                end else if (crc_count == 34) begin
691	                    crc_in_stb <= 0;
692	                end else if (crc_count == 35) begin
693	                    if (crc_out ^ crc) begin
694	                        status_code <= E_WRONG_CRC;
695	                        ht_sig_stb <= 1;
696	                        state <= S_HT_SIG_ERROR;
697	                    end else begin
698	                        `ifdef DEBUG_PRINT
699	                            $display("[HT SIGNAL] CRC OK");
700	                        `endif
701	                        ht_sig_crc_ok <= 1;
702	                        ht_sig_stb <= 1;
703	                        ofdm_reset <= 1;
704	                        state <= S_CHECK_HT_SIG;
705	                    end
706	                end
707	            end
708	
709	            S_CHECK_HT_SIG: begin
710	                ofdm_reset <= 0;
711	                ht_sig_stb <= 0;
712	                if (ht_mcs > 7) begin
713	                    status_code <= E_UNSUPPORTED_MCS;
714	                    state <= S_HT_SIG_ERROR;
715	                end else if (ht_cbw) begin
716	                    status_code <= E_UNSUPPORTED_CBW;
717	                    state <= S_HT_SIG_ERROR;
718	                end else if (ht_rsvd == 0) begin
719	                    status_code <= E_HT_WRONG_RSVD;
720	                    state <= S_HT_SIG_ERROR;
721	                end else if (ht_stbc != 0) begin
722	                    status_code <= E_UNSUPPORTED_STBC;
723	                    state <= S_HT_SIG_ERROR;
724	                end else if (ht_fec_coding) begin
725	                    status_code <= E_UNSUPPORTED_FEC;
726	                    state <= S_HT_SIG_ERROR;
727	                end else if (short_gi) begin
728	                    status_code <= E_UNSUPPORTED_SGI;
729	                    state <= S_HT_SIG_ERROR;
730	                end else if (ht_num_ext != 0) begin
731	                    status_code <= E_UNSUPPORTED_SPATIAL;
732	                    state <= S_HT_SIG_ERROR;
733	                end else if (ht_sig_tail != 0) begin
734	                    status_code <= E_HT_WRONG_TAIL;
735	                    state <= S_HT_SIG_ERROR;
736	                end else begin
737	                    sync_long_out_count <= 0;
738	                    state <= S_HT_STS;
739	                end
740	            end
741	
742	            S_HT_SIG_ERROR: begin
743	                ht_sig_stb <= 0;
744	                state <= S_WAIT_POWER_TRIGGER;
745	            end
746	
747	            S_HT_STS: begin
748	                if (sync_long_out_strobe) begin
749	                    sync_long_out_count <= sync_long_out_count + 1;
750	                end
751	                if (sync_long_out_count == 64) begin
752	                    sync_long_out_count <= 0;
753	                    ht_next <= 1;
754	                    state <= S_HT_LTS;
755	                end
756	            end
757	
758	            S_HT_LTS: begin
759	                short_gi <= ht_sgi;
760	                if (sync_long_out_strobe) begin
761	                    sync_long_out_count <= sync_long_out_count + 1;
762	                end
763	                if (sync_long_out_count == 64) begin
764	                    ht_next <= 0;
765	                    num_bits_to_decode <= (ht_len+3)<<4;
766	                    pkt_rate <= {1'b1, ht_mcs};
767	                    do_descramble <= 1;
768	                    ofdm_reset <= 1;
769	                    byte_count <= 0;
770	                    pkt_len <= ht_len;
771	                    pkt_begin <= 1;
772	                    pkt_ht <= 1;
773	                    state <= S_DECODE_DATA;
774	                end
775	            end
776	
777	            S_DECODE_DATA: begin
778	                pkt_begin <= 0;
779	                legacy_sig_stb <= 0;
780	
781	                if (ofdm_reset) begin
782	                    ofdm_reset <= 0;
783	                end
784	
785	                ofdm_in_stb <= eq_out_stb_delayed;
786	                ofdm_in_i <= eq_out_i_delayed;
787	                ofdm_in_q <= eq_out_q_delayed;
788	
789	                if (byte_out_strobe) begin
790	                    `ifdef DEBUG_PRINT
791	                        $display("[BYTE] [%4d / %-4d] %02x", byte_count+1, pkt_len,
792	                            byte_out);
793	                    `endif
794	                    byte_count <= byte_count + 1;
795	                end
796	
797	                if (byte_count >= pkt_len) begin
798	                    fcs_out_strobe <= 1;
799	                    if (pkt_fcs == EXPECTED_FCS) begin
800	                        fcs_ok <= 1;
801	                        status_code <= E_OK;
802	                    end else begin
803	                        fcs_ok <= 0;
804	                        status_code <= E_WRONG_FCS;
805	                    end
806	                    state <= S_DECODE_DONE;
807	                end
808	            end
809	
810	            S_DECODE_DONE: begin
811	                `ifdef DEBUG_PRINT
812	                    $display("===== PACKET DECODE DONE =====");
813	                    if (status_code == E_OK) begin
814	                        $display("FCS CORRECT");
815	                    end else begin
816	                        $display("FCS WRONG");
817	                    end
818	                `endif
819	                fcs_out_strobe <= 0;
820	                state <= S_WAIT_POWER_TRIGGER;
821	            end
822	
823	            default: begin
824	                state <= S_WAIT_POWER_TRIGGER;
825	            end
826	        endcase
827	    end
828	end
829	
830	endmodule
